mapper.select:
SELECT u.id, u.name, u.email, u.phone, u.avatar, u.nickName, u.last_login_time AS lastLoginTime, u.last_login_ip AS lastLoginIp, u.create_time AS createTime, GROUP_CONCAT(r.role_code ORDER BY r.id SEPARATOR ',') AS roleCodes, GROUP_CONCAT(r.role_name ORDER BY r.id SEPARATOR ',') AS roleNames FROM `sys_user` u LEFT JOIN `sys_user_role` ur ON u.id = ur.user_id LEFT JOIN `sys_role` r ON ur.role_id = r.id
AND u.name LIKE CONCAT('%', #{queryDTO.username}, '%') AND u.email LIKE CONCAT('%', #{queryDTO.email}, '%') AND u.phone LIKE CONCAT('%', #{queryDTO.phone}, '%') AND u.nickName LIKE CONCAT('%', #{queryDTO.nickName}, '%')
GROUP BY u.id, u.name, u.email, u.phone, u.avatar, u.nickName, u.last_login_time, u.last_login_ip, u.create_time ORDER BY u.id DESC LIMIT #{pageSize} OFFSET #{offset}

mapper.update:
UPDATE `sys_user`
email = #{email}, phone = #{phone}, nickName = #{nickName},
WHERE name = #{username}

UPDATE `sys_user`
email = #{email}, phone = #{phone}, nickName = #{nickName},
WHERE id = #{id}
